settings.nodeOpenedFunction:
var entity = nodeCtx.entity;

// Use the ID of your default device (find this from the ThingsBoard entity list)
var defaultDeviceId = '783e5900-45af-11ef-b4ce-d5aee9e495ad';

// Check if the current entity matches the default device and open it
if (entity.id.id === defaultDeviceId) {
    return true; // Open this device by default
} else {
    return nodeCtx.level <= 3; // Default behavior for other nodes (first level nodes open)
}

settings.nodeDisabledFunction:
var data = nodeCtx.data;
var excludedDevices = ['VPE Plant1', 'VPE Plant2', 'VPE Plant1_Block1','VPE Plant1_Block2', 'VPE Plant2_Block1','VPE Plant2_Block2', 'VPE P1_EnergyMeter', 'VPE P2_EnergyMeter', 'VPE P1_WSTN','VPE P2_WSTN'];
if (excludedDevices.includes(nodeCtx.entity.name)) {
    return true; // Disable these devices from being selectable
} else {
    return false;
}

settings.nodeIconFunction:
/** 

// Function should return node icon info object.
// Resulting object should contain either 'materialIcon' or 'iconUrl' property. 
// Where:
    - 'materialIcon' - name of the material icon to be used from the Material Icons Library (https://material.io/tools/icons);
    - 'iconUrl' - url of the external image to be used as node icon.
// Function can return 'default' string value. In this case default icons according to entity type will be used.

// The following example code shows how to use external image for devices which name starts with 'Test' and use 
// default icons for the rest of entities.

var entity = nodeCtx.entity;
if (entity.id.entityType === 'DEVICE' && entity.name.startsWith('Test')) {
    return {iconUrl: 'https://avatars1.githubusercontent.com/u/14793288?v=4&s=117'};
} else {
    return 'default';
}

**/

settings.nodeTextFunction:
var data = nodeCtx.data;
var entity = nodeCtx.entity;
var text = entity.label || entity.name;

// Check if the node is disabled
var isDisabled = false; // Default to not disabled

// Example logic to determine if node should be disabled
var excludedDevices = ['B1_STS', 'B1-Logger_eYpRyMMgoLpPGZG','Asset-KBG Plant', 'B2_STS', 'B2-Logger_AlfspQjyhvkmoVO', 'WSTN1', 'EnergyMeter'];
if (excludedDevices.includes(entity.name)) {
    isDisabled = true; // Mark the node as disabled
}

// Apply custom color based on whether the node is disabled
if (isDisabled) {
    text = '<span style="color: white;">' + text + '</span>'; // Set disabled node to gray
} else {
    text = '<span style="color: white;">' + text + '</span>'; // Set enabled nodes to black (or any other color)
}

return text;

