settings.markdownTextPattern:
var params = ctx.stateController.getStateParams();
var selectedAsset = params.SelectedAsset;
console.log("Selected Asset Params :", selectedAsset)
// Default to 'aggregated' to prevent a blank widget on first load
var targetState = 'aggregated'; 

if (selectedAsset && selectedAsset.entityName) {
    var name = selectedAsset.entityName;

    // 1. Check if the name ends with _Province or _District
    // We use a case-insensitive check or match the exact underscore pattern
    if (name.includes('_Province') || name.includes('_District')) {
        targetState = 'aggregated';
    } 
    // 2. Otherwise, if it's an asset but doesn't match the above, it's a Site
    else {
        targetState = 'site';
    }
}

return '<div class="state-wrapper" style="width: 100%; height: 100%;">' +
       '  <tb-dashboard-state ' +
       '    [ctx]="ctx" ' +
       '    stateId="' + targetState + '" ' +
       '    [syncParentStateParams]="true">' +
       '  </tb-dashboard-state>' +
       '</div>';

settings.markdownTextFunction:
var params = ctx.stateController.getStateParams();
var selectedAsset = params.SelectedAsset;
let dashboardmode = ctx.data[0].data?.[0]?.[1] || 1

console.log(dashboardmode)


console.log("Selected Asset Params :", selectedAsset)
// Default to 'aggregated' to prevent a blank widget on first load
var targetState = 'agg_ovr'; 
var issite=false;
if (selectedAsset && selectedAsset.entityName) {
    var name = selectedAsset.entityName;

    // 1. Check if the name ends with _Province or _District
    // We use a case-insensitive check or match the exact underscore pattern
    if (name.includes('_Province') || name.includes('_District') || name.includes("All Island")) {
        if(dashboardmode===1){
            targetState='agg_ovr';
        }else if(dashboardmode===3){
            targetState='asst_fin';
        }else if(dashboardmode===2){
            targetState = 'asset_maintenance';
        }
        
        //issite=false;
        //targetState = 'asset_dashboard1';
    }else if(name.includes('_Inverter')){
        targetState='site_inv';
    }
    // 2. Otherwise, if it's an asset but doesn't match the above, it's a Site
    else {
        targetState = 'site_ovr';
        if(dashboardmode===1){
            targetState='site_ovr';
        }else if(dashboardmode===2){
            targetState='site_anlytics';
        }else if(dashboardmode===3){
            targetState='site_fin';
        }
        //targetState = 'site_inv';
    }
}



return '<div class="state-wrapper" style="width: 100%; height: 100%;">' +
       '  <tb-dashboard-state ' +
       '    [ctx]="ctx" ' +
       '    stateId="' + targetState + '" ' +
       '    [syncParentStateParams]="true">' +
       '  </tb-dashboard-state>' +
       '</div>';

