settings.cardCss:
/* Remove default spacing */
html, body {
    height: 100%;
    margin: 0;
    padding: 0;
}

/* Main Card */
.string-card {
    height: 100%;
    width: 100%;
    box-sizing: border-box;

    background: #ffffff;
    border-radius: 12px;
    padding: 15px;

    font-family: 'Segoe UI', sans-serif;
    box-shadow: 0 2px 8px rgba(0,0,0,0.08);

    display: flex;
    flex-direction: column;
    overflow-y: auto;
}

/* Header */
.header {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 10px;
    color: #2c3e50;
}

/* Table Header */
.table-header {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    font-size: 0.75rem;
    font-weight: 600;
    color: #7f8c8d;
    padding: 8px 0;
    border-bottom: 1px solid #dfe6ec;
}

/* Rows Container */
.table-body {
    flex: 1;
    display: flex;
    flex-direction: column;
}

/* Rows */
.row {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    padding: 10px 0;
    border-bottom: 1px solid #e6ecf1;
    font-size: 2rem;
    align-items: center;
}

.row:last-child {
    border-bottom: none;
}

/* Voltage & Current Styling */
.voltage {
    color: #0077b6;
    font-weight: 500;
}

.current {
    color: #2e7d32;
    font-weight: 500;
}

/* ========================= */
/* Tablet View */
/* ========================= */
@media (max-width: 768px) {

    .string-card {
        padding: 12px;
        border-radius: 10px;
    }

    .header {
        font-size: 0.95rem;
    }

    .row {
        font-size: 0.8rem;
        padding: 8px 0;
    }

    .table-header {
        font-size: 0.7rem;
    }
}

/* ========================= */
/* Mobile View */
/* ========================= */
@media (max-width: 480px) {

    .string-card {
        padding: 10px;
        border-radius: 8px;
    }

    .header {
        font-size: 0.9rem;
        margin-bottom: 8px;
    }

    .table-header,
    .row {
        grid-template-columns: 0.8fr 1fr 1fr;
        font-size: 0.75rem;
    }

    .row {
        padding: 6px 0;
    }
}

